import io
import torch
from torchvision import models, transforms
from PIL import Image, UnidentifiedImageError
from fastapi import FastAPI, UploadFile, File, HTTPException
import json # Used for potentially loading ImageNet class labels

# Initialize FastAPI app
app = FastAPI()

# --- Model Loading and Configuration ---
# Use a pre-trained ResNet model (e.g., ResNet18)
# You can choose other models like resnet34, resnet50, vgg16, etc.
# Make sure to install torchvision: pip install torchvision
model = models.resnet18(weights=models.ResNet18_Weights.IMAGENET1K_V1)
model.eval() # Set the model to evaluation mode

# Determine device (CPU or GPU if available)
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
model.to(device)

# --- ImageNet Class Labels ---
# For a production system, you would typically load these from a file.
# You can download the full ImageNet 1k class labels from here:
# https://raw.githubusercontent.com/pytorch/hub/master/imagenet_classes.txt
# Save it as 'imagenet_classes.txt' in the same directory as this script.
try:
    with open("imagenet_classes.txt") as f:
        imagenet_labels = [line.strip() for line in f.readlines()]
except FileNotFoundError:
    print(
        "WARNING: imagenet_classes.txt not found. "
        "Using a default/dummy list of labels. "
        "Please download from "
        "https://raw.githubusercontent.com/pytorch/hub/master/imagenet_classes.txt "
        "for accurate results."
    )
    # Provide a placeholder list if the file is not found
    imagenet_labels = [f"class_{i}" for i in range(1000)]
    # Add a few common ones for demonstration if the file isn't present
    imagenet_labels[0] = "tench, Tinca tinca"
    imagenet_labels[281] = "tiger cat"
    imagenet_labels[907] = "pizza, pizza pie"

# --- Preprocessing Transforms ---
# These are standard transforms required for pre-trained ImageNet models
# to convert an input image into the format expected by the neural network.
# The user requested "without preprocessing", which in the context of PyTorch
# usually means "without *additional custom logic* or *complex validation* beyond
# what's intrinsically required for the model's input format."
# These transforms (resize, crop, convert to tensor, normalize) are fundamental
# steps for almost any pre-trained PyTorch vision model.
preprocess = transforms.Compose([
    transforms.Resize(256),       # Resize the image to 256x256 pixels
    transforms.CenterCrop(224),   # Crop the center 224x224 portion (ResNet input size)
    transforms.ToTensor(),        # Convert PIL Image to PyTorch Tensor (HWC to CHW, scales to [0,1])
    transforms.Normalize(         # Normalize with ImageNet's mean and standard deviation
        mean=[0.485, 0.456, 0.406],
        std=[0.229, 0.224, 0.225]
    ),
])

# --- API Endpoint ---
@app.post("/classify-image")
async def classify_image(file: UploadFile = File(...)):
    """
    Receives an image via HTTP POST, runs PyTorch inference, and returns
    the predicted class and confidence score.
    """
    try:
        # Read image file contents
        contents = await file.read()

        # Open the image using PIL (Pillow)
        # .convert("RGB") ensures the image has 3 channels, converting from
        # grayscale, RGBA, etc., as most ImageNet models expect 3-channel input.
        image = Image.open(io.BytesIO(contents)).convert("RGB")

    except UnidentifiedImageError:
        raise HTTPException(
            status_code=400,
            detail="Could not identify image file. Please ensure it's a valid image format (e.g., JPEG, PNG)."
        )
    except Exception as e:
        # Catch any other potential errors during image loading
        raise HTTPException(
            status_code=500,
            detail=f"An unexpected error occurred while processing the image: {e}"
        )

    # Apply preprocessing transforms
    input_tensor = preprocess(image)

    # Add a batch dimension (PyTorch models expect input in BxCxHxW format)
    input_batch = input_tensor.unsqueeze(0)

    # Move the input tensor to the correct device (CPU/GPU)
    input_batch = input_batch.to(device)

    with torch.no_grad():  # Disable gradient calculation for inference to save memory and speed up
        output = model(input_batch)

    # Get probabilities by applying softmax to the model's output
    probabilities = torch.nn.functional.softmax(output[0], dim=0)

    # Get the predicted class index and its confidence score
    confidence, predicted_class_idx = torch.max(probabilities, 0)

    # Convert tensors to Python native types for JSON serialization
    confidence_score = confidence.item()
    predicted_class_index = predicted_class_idx.item()

    # Get the predicted class name using the ImageNet labels list
    predicted_class_name = imagenet_labels[predicted_class_index]

    return {
        "predicted_class": predicted_class_name,
        "confidence": confidence_score
    }

